import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.c3r8iWL8.js";const u=JSON.parse('{"title":"SOP-010: AI Tool Usage & Data Handling","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"sops/SOP-010-ai-tool-usage.md","filePath":"sops/SOP-010-ai-tool-usage.md","lastUpdated":1782929962000}'),i={name:"sops/SOP-010-ai-tool-usage.md"};function n(l,e,d,s,p,c){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="sop-010-ai-tool-usage-data-handling" tabindex="-1">SOP-010: AI Tool Usage &amp; Data Handling <a class="header-anchor" href="#sop-010-ai-tool-usage-data-handling" aria-label="Permalink to &quot;SOP-010: AI Tool Usage &amp; Data Handling&quot;">‚Äã</a></h1><p><strong>Version:</strong> 1.0 ¬∑ <strong>Owner:</strong> AI Platform Owner + Security ¬∑ <strong>Applies to:</strong> All engineers</p><h2 id="purpose-scope" tabindex="-1">Purpose &amp; scope <a class="header-anchor" href="#purpose-scope" aria-label="Permalink to &quot;Purpose &amp; scope&quot;">‚Äã</a></h2><p>Safe, compliant use of AI coding and planning tools (Cursor, Amazon Q, Bedrock agents, MCP).</p><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">‚Äã</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>RACI</th></tr></thead><tbody><tr><td>AIPO</td><td><strong>A</strong> ‚Äî platform config, audit</td></tr><tr><td>SEC</td><td><strong>A</strong> ‚Äî data classification rules</td></tr><tr><td>DEV</td><td><strong>R</strong> ‚Äî compliant daily use</td></tr></tbody></table><h2 id="approved-tools-primary-stack" tabindex="-1">Approved tools (primary stack) <a class="header-anchor" href="#approved-tools-primary-stack" aria-label="Permalink to &quot;Approved tools (primary stack)&quot;">‚Äã</a></h2><table tabindex="0"><thead><tr><th>Tool</th><th>Use</th><th>Data boundary</th></tr></thead><tbody><tr><td>Cursor (enterprise)</td><td>IDE + agents</td><td>No prod PII; enterprise privacy mode</td></tr><tr><td>Amazon Q Developer</td><td>AWS API / IaC help</td><td>AWS enterprise boundary</td></tr><tr><td>Bedrock (via gateway)</td><td>Planning agents, batch tasks</td><td>VPC endpoint; logged prompts</td></tr><tr><td>MCP (internal)</td><td>ADR, spec, runbook search</td><td>Read-only; Accepted/Approved only</td></tr></tbody></table><p>Optional (team discretion): local Ollama for offline snippets ‚Äî <strong>no company code</strong>.</p><h2 id="procedure" tabindex="-1">Procedure <a class="header-anchor" href="#procedure" aria-label="Permalink to &quot;Procedure&quot;">‚Äã</a></h2><h3 id="before-use" tabindex="-1">Before use <a class="header-anchor" href="#before-use" aria-label="Permalink to &quot;Before use&quot;">‚Äã</a></h3><ol><li>Confirm enterprise AI agreements active; privacy mode on in Cursor.</li><li>Complete onboarding module (SOP-011 step 5).</li></ol><h3 id="during-development" tabindex="-1">During development <a class="header-anchor" href="#during-development" aria-label="Permalink to &quot;During development&quot;">‚Äã</a></h3><ol start="3"><li><strong>Context hygiene</strong> ‚Äî Load Approved spec + Accepted ADRs via MCP; avoid pasting large prod log dumps.</li><li><strong>No prohibited data in prompts</strong> ‚Äî Prod PII, credentials, full customer records, unredacted security findings.</li><li><strong>Synthetic fixtures only</strong> ‚Äî Test data generated or from approved fixture library.</li><li><strong>Verify AI output</strong> ‚Äî Never merge unreviewed AI-generated code; treat as untrusted input.</li></ol><h3 id="prohibited" tabindex="-1">Prohibited <a class="header-anchor" href="#prohibited" aria-label="Permalink to &quot;Prohibited&quot;">‚Äã</a></h3><ul><li>Pasting production database exports into AI chat</li><li>Sending secrets, API keys, or <code>.env</code> contents to models</li><li>Using personal ChatGPT accounts for company code</li><li>Auto-accepting AI architectural decisions (‚Üí SOP-002)</li></ul><h3 id="audit" tabindex="-1">Audit <a class="header-anchor" href="#audit" aria-label="Permalink to &quot;Audit&quot;">‚Äã</a></h3><ol start="7"><li>AIPO samples 1% of enterprise AI logs monthly for policy violations.</li><li>Violations ‚Üí SEC review; repeat ‚Üí access restriction per <a href="./SOP-012-exception-handling.html">SOP-012</a>.</li></ol><h2 id="definition-of-done-ongoing" tabindex="-1">Definition of Done (ongoing) <a class="header-anchor" href="#definition-of-done-ongoing" aria-label="Permalink to &quot;Definition of Done (ongoing)&quot;">‚Äã</a></h2><ul><li>[ ] Developer acknowledged AI policy annually</li><li>[ ] No open SEC violations on AI usage</li></ul><h2 id="related-sops" tabindex="-1">Related SOPs <a class="header-anchor" href="#related-sops" aria-label="Permalink to &quot;Related SOPs&quot;">‚Äã</a></h2><ul><li><a href="./SOP-004-implementation.html">SOP-004</a> ¬∑ <a href="./SOP-011-onboarding.html">SOP-011</a> ¬∑ <a href="./SOP-012-exception-handling.html">SOP-012</a></li></ul>',22)])])}const g=t(i,[["render",n]]);export{u as __pageData,g as default};
